class AdMobBanner extends StatefulWidget{ const AdMobBanner({super.key}); @override State<AdMobBanner> createState()=>_AdMobBannerState(); }
class _AdMobBannerState extends State<AdMobBanner>{ BannerAd? ad; bool loaded=false; @override void initState(){ super.initState(); WidgetsBinding.instance.addPostFrameCallback((_)=>loadAd()); } Future<void> loadAd() async{ try{ await MobileAds.instance.initialize(); final banner=BannerAd(adUnitId:admobBannerUnitId,size:AdSize.banner,request:const AdRequest(),listener:BannerAdListener(onAdLoaded:(_){if(mounted)setState(()=>loaded=true);},onAdFailedToLoad:(failedAd,error){failedAd.dispose(); if(mounted)setState(()=>loaded=false);})); ad=banner; await banner.load(); }catch(_){ ad?.dispose(); ad=null; if(mounted)setState(()=>loaded=false); } } @override void dispose(){ ad?.dispose(); super.dispose(); } @override Widget build(BuildContext context){ if(!loaded||ad==null)return const SizedBox.shrink(); return Container(height:ad!.size.height.toDouble(),width:double.infinity,alignment:Alignment.center,margin:const EdgeInsets.fromLTRB(14,8,14,8),child:SizedBox(width:ad!.size.width.toDouble(),height:ad!.size.height.toDouble(),child:AdWidget(ad:ad!))); }}

enum DebtType { lent, borrowed }

class Person{ String id,name; int createdAt; Person(this.id,this.name,this.createdAt); Map<String,dynamic> toJson()=>{'id':id,'name':name,'createdAt':createdAt}; factory Person.fromJson(Map<String,dynamic> j)=>Person(j['id']??'',j['name']??'',j['createdAt']??DateTime.now().millisecondsSinceEpoch); }
class Entry{ String id,personId,category,note; DebtType type; double amount,settledAmount; int createdAt; int? dueAt; bool settled; Entry({required this.id,required this.personId,required this.type,required this.amount,required this.settledAmount,required this.category,required this.note,required this.createdAt,this.dueAt,this.settled=false}); double get remaining => max(0, amount-settledAmount); Map<String,dynamic> toJson()=>{'id':id,'personId':personId,'type':type.name,'amount':amount,'settledAmount':settledAmount,'category':category,'note':note,'createdAt':createdAt,'dueAt':dueAt,'settled':settled}; factory Entry.fromJson(Map<String,dynamic> j)=>Entry(id:j['id']??'',personId:j['personId']??'',type:(j['type']??'lent')=='borrowed'?DebtType.borrowed:DebtType.lent,amount:(j['amount']??0).toDouble(),settledAmount:(j['settledAmount']??0).toDouble(),category:j['category']??'مال',note:j['note']??'',createdAt:j['createdAt']??DateTime.now().millisecondsSinceEpoch,dueAt:j['dueAt'],settled:j['settled']??false); }

class Store{ static final I=Store._(); Store._(); List<Person> people=[]; List<Entry> entries=[]; String currency='دولار'; bool notifications=true, sounds=true, showSettled=true; String id()=>'${DateTime.now().millisecondsSinceEpoch}_${Random().nextInt(999999)}';
Future<void> load() async{ final p=await SharedPreferences.getInstance(); currency=p.getString('currency')??'دولار'; notifications=p.getBool('notifications')??true; sounds=p.getBool('sounds')??true; showSettled=p.getBool('showSettled')??true; final rp=p.getString('people'); if(rp!=null) people=(jsonDecode(rp) as List).map((e)=>Person.fromJson(Map<String,dynamic>.from(e))).toList(); final re=p.getString('entries'); if(re!=null) entries=(jsonDecode(re) as List).map((e)=>Entry.fromJson(Map<String,dynamic>.from(e))).toList(); }
Future<void> save() async{ final p=await SharedPreferences.getInstance(); await p.setString('currency',currency); await p.setBool('notifications',notifications); await p.setBool('sounds',sounds); await p.setBool('showSettled',showSettled); await p.setString('people',jsonEncode(people.map((e)=>e.toJson()).toList())); await p.setString('entries',jsonEncode(entries.map((e)=>e.toJson()).toList())); }
Person? person(String id){ try{return people.firstWhere((p)=>p.id==id);}catch(_){return null;} }
Person findOrCreate(String name){ final clean=name.trim(); for(final p in people){ if(p.name.trim().toLowerCase()==clean.toLowerCase()) return p; } final p=Person(id(),clean,DateTime.now().millisecondsSinceEpoch); people.add(p); return p; }
Future<void> add({required String personName,required DebtType type,required double amount,required String category,required String note,required int? dueAt,int? createdAt}) async{ final p=findOrCreate(personName); entries.add(Entry(id:id(),personId:p.id,type:type,amount:amount,settledAmount:0,category:category,note:note,createdAt:createdAt??DateTime.now().millisecondsSinceEpoch,dueAt:dueAt)); await save(); }
Future<void> deletePerson(String pid) async{ entries.removeWhere((e)=>e.personId==pid); people.removeWhere((p)=>p.id==pid); await save(); }
Future<void> deleteEntry(String id) async{ entries.removeWhere((e)=>e.id==id); await save(); }
Future<void> settle(String id,{double? amount}) async{ final e=entries.firstWhere((x)=>x.id==id); e.settledAmount+=amount??e.remaining; if(e.settledAmount>=e.amount){e.settledAmount=e.amount; e.settled=true;} await save(); }
List<Entry> entriesFor(String pid){ final l=entries.where((e)=>e.personId==pid && (showSettled || !e.settled)).toList(); l.sort((a,b)=>b.createdAt.compareTo(a.createdAt)); return l; }
double lent(String pid)=>entries.where((e)=>e.personId==pid&&e.type==DebtType.lent&&!e.settled).fold(0,(s,e)=>s+e.remaining); double borrowed(String pid)=>entries.where((e)=>e.personId==pid&&e.type==DebtType.borrowed&&!e.settled).fold(0,(s,e)=>s+e.remaining); double net(String pid)=>lent(pid)-borrowed(pid); double totalLent()=>people.fold(0,(s,p)=>s+lent(p.id)); double totalBorrowed()=>people.fold(0,(s,p)=>s+borrowed(p.id)); int lentCount()=>entries.where((e)=>e.type==DebtType.lent&&!e.settled).length; int borrowedCount()=>entries.where((e)=>e.type==DebtType.borrowed&&!e.settled).length; List<Person> activePeople(){ final ids=entries.map((e)=>e.personId).toSet(); final r=people.where((p)=>ids.contains(p.id)).toList(); r.sort((a,b){ int la=0,lb=0; for(final e in entries){ if(e.personId==a.id) la=max(la,e.createdAt); if(e.personId==b.id) lb=max(lb,e.createdAt);} return lb.compareTo(la);}); return r; }}

