Future<void> settleDialog(Entry e)async{ final c=TextEditingController(text:money(e.remaining)); final ok=await showDialog<bool>(context:context,builder:(_)=>Directionality(textDirection:TextDirection.rtl,child:AlertDialog(backgroundColor:darkPanel,title:const Text('تسوية العملية',style:TextStyle(color:textMain)),content:TextField(controller:c,keyboardType:const TextInputType.numberWithOptions(decimal:true),style:const TextStyle(color:textMain),decoration:const InputDecoration(hintText:'المبلغ المسدد')),actions:[TextButton(onPressed:()=>Navigator.pop(context,false),child:const Text('إلغاء')),FilledButton(onPressed:()=>Navigator.pop(context,true),child:const Text('تسوية'))]))); if(ok==true){ await s.settle(e.id,amount:double.tryParse(c.text.replaceAll(',','.'))??e.remaining); await appFeedback('settle.wav'); setState((){});} }
Future<bool> deleteDialog(Entry e)async{ final ok=await showDialog<bool>(context:context,builder:(_)=>Directionality(textDirection:TextDirection.rtl,child:AlertDialog(backgroundColor:darkPanel,title:const Text('حذف العملية',style:TextStyle(color:textMain)),content:const Text('هل تريد حذف هذه العملية؟',style:TextStyle(color:textSoft)),actions:[TextButton(onPressed:()=>Navigator.pop(context,false),child:const Text('إلغاء')),FilledButton(onPressed:()=>Navigator.pop(context,true),child:const Text('حذف'))]))); if(ok==true){await s.deleteEntry(e.id); await appFeedback('delete.wav'); setState((){}); return true;} return false; }
void shareStatement(){
  final all=s.entries.where((e)=>e.personId==widget.person.id).toList()..sort((a,b)=>b.createdAt.compareTo(a.createdAt));
  final active=all.where((e)=>!e.settled).toList();
  final totalLent=active.where((e)=>e.type==DebtType.lent).fold<double>(0,(sum,e)=>sum+e.remaining);
  final totalBorrowed=active.where((e)=>e.type==DebtType.borrowed).fold<double>(0,(sum,e)=>sum+e.remaining);
  final n=totalLent-totalBorrowed;
  final lines=<String>[
    'دفتر الديون',
    'كشف حساب: ${widget.person.name}',
    'تاريخ الكشف: ${dateOnly(DateTime.now().millisecondsSinceEpoch)}',
    '------------------------------',
    'لي عنده: ${money(totalLent)} ${s.currency}',
    'علي له: ${money(totalBorrowed)} ${s.currency}',
    n==0?'الصافي: لا يوجد رصيد':n>0?'الصافي: لك ${money(n.abs())} ${s.currency}':'الصافي: عليك ${money(n.abs())} ${s.currency}',
    '------------------------------',
    'تفاصيل العمليات:',
  ];
  if(all.isEmpty){
    lines.add('لا توجد عمليات مسجلة.');
  } else {
    for(var i=0;i<all.length;i++){
      final e=all[i];
      final action=e.type==DebtType.lent?'أعطيت':'أخذت';
      final status=e.settled?'مسددة بالكامل':e.settledAmount>0?'مسددة جزئيًا':'غير مسددة';
      lines.add('${i+1}) $action');
      lines.add('   المبلغ الأصلي: ${money(e.amount)} ${s.currency}');
      lines.add('   المسدد: ${money(e.settledAmount)} ${s.currency}');
      lines.add('   المتبقي: ${money(e.remaining)} ${s.currency}');
      lines.add('   الحالة: $status');
      lines.add('   تاريخ العملية: ${dateOnly(e.createdAt)}');
      if(e.dueAt!=null) lines.add('   موعد السداد: ${dateOnly(e.dueAt!)}');
      if(e.note.trim().isNotEmpty) lines.add('   ملاحظة: ${e.note.trim()}');
      lines.add('------------------------------');
    }
  }
  lines.add('تم إنشاء الكشف من تطبيق دفتر الديون');
  Share.share(lines.join('\n'),subject:'كشف حساب ${widget.person.name}');
}}

